const express = require('express');
const { graphqlHTTP } = require('express-graphql');
const {
  GraphQLSchema,
  GraphQLObjectType,
  GraphQLString,
  GraphQLInt,
  GraphQLList,
  GraphQLNonNull,
} = require('graphql');
const { Pool } = require('pg');
const {
  createComplexityLimitRule,
} = require('graphql-validation-complexity');
const depthLimit = require('graphql-depth-limit');

const pool = new Pool({
  host: process.env.PG_HOST || 'localhost',
  port: parseInt(process.env.PG_PORT, 10) || 5432,
  database: process.env.PG_DATABASE || 'blog',
  user: process.env.PG_USER || 'postgres',
  password: process.env.PG_PASSWORD || 'postgres',
});

async function initializeDatabase() {
  const client = await pool.connect();
  try {
    await client.query(`
      CREATE TABLE IF NOT EXISTS authors (
        id SERIAL PRIMARY KEY,
        name VARCHAR(255) NOT NULL,
        email VARCHAR(255) UNIQUE NOT NULL
      );
    `);

    await client.query(`
      CREATE TABLE IF NOT EXISTS posts (
        id SERIAL PRIMARY KEY,
        title VARCHAR(255) NOT NULL,
        body TEXT NOT NULL,
        author_id INTEGER NOT NULL REFERENCES authors(id) ON DELETE CASCADE
      );
    `);

    const { rows } = await client.query('SELECT COUNT(*) FROM authors');
    if (parseInt(rows[0].count, 10) === 0) {
      await client.query(`
        INSERT INTO authors (name, email) VALUES
          ('Alice Johnson', 'alice@example.com'),
          ('Bob Smith', 'bob@example.com'),
          ('Carol White', 'carol@example.com');
      `);

      await client.query(`
        INSERT INTO posts (title, body, author_id) VALUES
          ('Introduction to GraphQL', 'GraphQL is a query language for APIs...', 1),
          ('Node.js Best Practices', 'When building Node.js applications...', 1),
          ('PostgreSQL Tips', 'PostgreSQL is a powerful relational database...', 2),
          ('Express Middleware Guide', 'Middleware functions in Express...', 3),
          ('Understanding Resolvers', 'Resolvers are the building blocks...', 2);
      `);

      console.log('Seed data inserted.');
    }
  } finally {
    client.release();
  }
}

const AuthorType = new GraphQLObjectType({
  name: 'Author',
  fields: () => ({
    id: { type: new GraphQLNonNull(GraphQLInt) },
    name: { type: new GraphQLNonNull(GraphQLString) },
    email: { type: new GraphQLNonNull(GraphQLString) },
    posts: {
      type: new GraphQLList(PostType),
      async resolve(parent) {
        const { rows } = await pool.query(
          'SELECT * FROM posts WHERE author_id = $1',
          [parent.id]
        );
        return rows;
      },
    },
  }),
});

const PostType = new GraphQLObjectType({
  name: 'Post',
  fields: () => ({
    id: { type: new GraphQLNonNull(GraphQLInt) },
    title: { type: new GraphQLNonNull(GraphQLString) },
    body: { type: new GraphQLNonNull(GraphQLString) },
    author_id: { type: new GraphQLNonNull(GraphQLInt) },
    author: {
      type: AuthorType,
      async resolve(parent) {
        const { rows } = await pool.query(
          'SELECT * FROM authors WHERE id = $1',
          [parent.author_id]
        );
        return rows[0] || null;
      },
    },
  }),
});

const RootQueryType = new GraphQLObjectType({
  name: 'Query',
  fields: {
    post: {
      type: PostType,
      args: {
        id: { type: new GraphQLNonNull(GraphQLInt) },
      },
      async resolve(_, args) {
        const { rows } = await pool.query(
          'SELECT * FROM posts WHERE id = $1',
          [args.id]
        );
        return rows[0] || null;
      },
    },
    posts: {
      type: new GraphQLList(PostType),
      args: {
        limit: { type: GraphQLInt },
        offset: { type: GraphQLInt },
      },
      async resolve(_, args) {
        const limit = Math.min(Math.max(args.limit || 25, 1), 100);
        const offset = Math.max(args.offset || 0, 0);
        const { rows } = await pool.query(
          'SELECT * FROM posts ORDER BY id LIMIT $1 OFFSET $2',
          [limit, offset]
        );
        return rows;
      },
    },
    author: {
      type: AuthorType,
      args: {
        id: { type: new GraphQLNonNull(GraphQLInt) },
      },
      async resolve(_, args) {
        const { rows } = await pool.query(
          'SELECT * FROM authors WHERE id = $1',
          [args.id]
        );
        return rows[0] || null;
      },
    },
    authors: {
      type: new GraphQLList(AuthorType),
      args: {
        limit: { type: GraphQLInt },
        offset: { type: GraphQLInt },
      },
      async resolve(_, args) {
        const limit = Math.min(Math.max(args.limit || 25, 1), 100);
        const offset = Math.max(args.offset || 0, 0);
        const { rows } = await pool.query(
          'SELECT * FROM authors ORDER BY id LIMIT $1 OFFSET $2',
          [limit, offset]
        );
        return rows;
      },
    },
  },
});

const schema = new GraphQLSchema({
  query: RootQueryType,
});

const QUERY_DEPTH_LIMIT = 5;
const COMPLEXITY_LIMIT = 1000;

const validationRules = [
  depthLimit(QUERY_DEPTH_LIMIT),
  createComplexityLimitRule(COMPLEXITY_LIMIT, {
    onCost: (cost) => {
      console.log(`Query complexity: ${cost}`);
    },
  }),
];

const app = express();

app.use(express.json({ limit: '100kb' }));

app.disable('x-powered-by');

const isProduction = process.env.NODE_ENV === 'production';

app.use(
  '/graphql',
  graphqlHTTP({
    schema,
    graphiql: !isProduction,
    validationRules,
    customFormatErrorFn: (error) => {
      console.error('GraphQL Error:', error);
      if (isProduction) {
        return {
          message: error.message,
          path: error.path,
        };
      }
      return {
        message: error.message,
        locations: error.locations,
        path: error.path,
      };
    },
  })
);

const PORT = parseInt(process.env.PORT, 10) || 4000;

initializeDatabase()
  .then(() => {
    app.listen(PORT, () => {
      console.log(`GraphQL API running at http://localhost:${PORT}/graphql`);
      if (!isProduction) {
        console.log(`GraphiQL available at http://localhost:${PORT}/graphql`);
      }
      console.log(`Security: depth limit=${QUERY_DEPTH_LIMIT}, complexity limit=${COMPLEXITY_LIMIT}`);
    });
  })
  .catch((err) => {
    console.error('Failed to initialize database:', err);
    process.exit(1);
  });

process.on('SIGTERM', async () => {
  console.log('Shutting down...');
  await pool.end();
  process.exit(0);
});

process.on('SIGINT', async () => {
  console.log('Shutting down...');
  await pool.end();
  process.exit(0);
});

module.exports = { app, pool, schema };